network.ethernets:
{% for nic_name,nic_conf in ethernets.items() %}
<{{nic_name}}>

    {% for ip in nic_conf['addresses'] %}
        {{ip}}
    {% endfor %}



        {% for domain in nic_conf['nameservers']['search'] %}
            {{domain}}
        {% endfor %}
        >

        {% for addr in nic_conf['nameservers']['addresses'] %}
            {{addr}}
        {% endfor %}


</{{nic_name}}>
{% endfor %}
